import numpy as np

def compute_bm25_term(tf, idf, doc_len, avg_len, k1=1.5, b=0.75):
    numerator = tf * (k1 + 1.0)
    denominator = tf + k1 * (1.0 - b + b * (doc_len / avg_len))
    return idf * (numerator / denominator)

def run_practice():
    score = compute_bm25_term(0.0, 1.0, 100, 100)
    assert score == 0.0
    print('[PASS] BM25 zero tf check validated.')

if __name__ == '__main__':
    run_practice()
